// === Preparar Paths ===
// VERSAO ZERO RE-ENCODE DE VIDEO (corrige o OOM "n8n may have run out of memory").
// Esta versao NAO recodifica o video (zero re-encode de video por software):
// recodificar o video inteiro
// 1080x1920 era a passada que estourava a RAM do servidor. Aqui o video so passa por
// STREAM COPY (concat demuxer com -c copy) e, quando ha musica, por -c:v copy (apenas
// o audio e recodificado, mixagem leve). O CTA queimado no quadro foi REMOVIDO de
// proposito: o CTA passa a ser feito via HyperFrames e a ultima narracao do roteiro
// ja e o proprio CTA, entao nao ha mais nenhuma passada de re-encode de video aqui.
// ASYNC: usa exec via wrapper Promise manual sobre child_process.exec (sem o modulo util).
const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');
function execAsync(cmd, opts) {
  return new Promise(function (resolve, reject) {
    exec(cmd, opts, function (err, stdout, stderr) {
      if (err) { reject(err); } else { resolve({ stdout: stdout, stderr: stderr }); }
    });
  });
}
const EXEC_OPTS = { timeout: 300000, maxBuffer: 1024 * 1024 * 64 };
const NL = String.fromCharCode(10);
const TMP = '/tmp';

function resolverCaminho(bin) {
  if (!bin) return null;
  const id = bin.id ? String(bin.id).split(':').pop() : null;
  const candidatos = [];
  if (id) {
    candidatos.push(
      path.join('/home/node/.n8n/binaryData', id),
      path.join('/home/node/.n8n/binaryData', id + '.bin'),
      path.join('/data/.n8n/binaryData', id),
      path.join('/tmp', id)
    );
  }
  for (const c of candidatos) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return null;
}

async function getBuf(idx, prop, bin) {
  try {
    const b = await this.helpers.getBinaryDataBuffer(idx, prop);
    if (b && b.length) return b;
  } catch (e) {}
  const p = resolverCaminho(bin && bin[prop]);
  if (p) { try { return fs.readFileSync(p); } catch (e) {} }
  return null;
}

// 1) Le cada clip (binary "data") em ordem e escreve em /tmp.
//    Para nao acumular memoria, NAO guardamos os buffers: escreve e descarta (buf = null).
const items = $input.all();
const clipPaths = [];
let articleTitle = 'video_dje';
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  if (items[i].json && items[i].json.articleTitle) articleTitle = items[i].json.articleTitle;
  let buf = await getBuf.call(this, i, 'data', bin);
  if (!buf) continue;
  const p = `${TMP}/seg_${i}.mp4`;
  fs.writeFileSync(p, buf);
  buf = null; // libera a referencia do buffer imediatamente
  clipPaths.push(p);
}

if (clipPaths.length === 0) {
  throw new Error('Nenhum clip disponivel para concatenar.');
}

// 2) Concatena com o CONCAT DEMUXER em STREAM COPY (-c copy = nao recodifica nada).
//    Os clips tem o mesmo codec/params (gerados igualmente pelo "Preparar Arquivos"),
//    entao o -c copy funciona sem reabrir/decodificar os videos. O list.txt usa
//    quebras de linha via String.fromCharCode(10) (PASTE-SAFE).
const listPath = `${TMP}/list.txt`;
const listLines = clipPaths.map(function (p) { return "file '" + p + "'"; });
fs.writeFileSync(listPath, listLines.join(NL) + NL);
const concatPath = `${TMP}/concat.mp4`;
await execAsync(`ffmpeg -y -f concat -safe 0 -i "${listPath}" -c copy "${concatPath}"`, EXEC_OPTS);

// 3) Musica de fundo opcional (URL do formulario, baixada via wget como antes).
let musicaUrl = '';
try {
  const fdata = $('Formulario de Video').first().json || {};
  musicaUrl = String(fdata['Musica de Fundo (URL)'] || '').trim();
} catch (e) { musicaUrl = ''; }

const musicPath = `${TMP}/bg_music.mp3`;
let temMusica = false;
if (musicaUrl) {
  try {
    await execAsync(`wget -q --user-agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36" -O "${musicPath}" "${musicaUrl}"`, { timeout: 120000, maxBuffer: 1024 * 1024 * 16 });
    temMusica = (function () { try { return fs.existsSync(musicPath) && fs.statSync(musicPath).size > 4096; } catch (e) { return false; } })();
  } catch (e) { temMusica = false; }
}

// 4) Com musica: mixa SEM recodificar o video (-c:v copy = video intacto, leve).
//    Reduz o volume da musica para 0.12 e mixa com o audio original das narracoes;
//    apenas o audio resultante e recodificado para aac.
const finalPath = `${TMP}/final.mp4`;
let sucesso = false;
if (temMusica) {
  try {
    await execAsync(`ffmpeg -y -i "${concatPath}" -stream_loop -1 -i "${musicPath}" -filter_complex "[1:a]volume=0.12[bg];[0:a][bg]amix=inputs=2:duration=first:dropout_transition=2:normalize=0[a]" -map 0:v -c:v copy -map "[a]" -c:a aac -b:a 192k -shortest -movflags +faststart "${finalPath}"`, EXEC_OPTS);
    sucesso = fs.existsSync(finalPath) && fs.statSync(finalPath).size > 0;
  } catch (e) {
    sucesso = false;
  }
}

// 5) Fallback gracioso: sem musica (ou se a mixagem falhar) o resultado final e o
//    proprio concat.mp4 (stream copy puro), sem nenhuma passada extra.
const saidaPath = sucesso ? finalPath : concatPath;

// 6) Retorno final: json { articleTitle, fileName } + binary { data }.
const finalBuf = fs.readFileSync(saidaPath);
const nomeArquivo = `${articleTitle}.mp4`;
return [{
  json: { articleTitle: articleTitle, fileName: nomeArquivo },
  binary: { data: await this.helpers.prepareBinaryData(finalBuf, nomeArquivo, 'video/mp4') }
}];
